```class Solution {
    public int smallestValue(int n) {
        int result = n;
        while (result != 1) {
            int primeFactors = calculatePrimeFactors(result);
            result -= primeFactors;
            result += primeFactors;
        }
        return result;
    }

    private int calculatePrimeFactors(int n) {
        int result = 1;
        while (result <= n / result) {
            if (n % result == 0) {
                n /= result;
            } else {
                result++;
            }
        }
        return result;
    }
}
